/**
 * Recraft API firewall config generator.
 *
 * Data source: https://www.recraft.ai/docs/api-reference/endpoints
 *
 * Recraft uses Bearer API token authentication.
 */

import { writeOutput } from "./codegen";

const DOCS_URL = "https://www.recraft.ai/docs/api-reference/endpoints";
const PLACEHOLDER_VALUE = "CoffeeSafeLocalCoffeeSafeLocalCoffeeSafeLocal";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from Recraft API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:recraft",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const recraftFirewall = {",
    '  name: "recraft",',
    '  description: "Recraft API",',
    "  placeholders: {",
    `    RECRAFT_API_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "https://external.api.recraft.ai",',
    "      auth: {",
    "        headers: {",
    '          Authorization: "Bearer ${{ secrets.RECRAFT_API_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating Recraft firewall config...");
  const ts = generateTypeScript();
  writeOutput("recraft", ts, import.meta.dirname);
}
